APP_NAME = "office-face-recognition-api"
DEFAULT_MODEL_PATH = os.environ.get("FACE_MODEL_PATH", "./face_model.pkl")
DEFAULT_TRAIN_DIR = os.environ.get("FACE_TRAIN_DIR", "./employees")
DEFAULT_API_KEY = os.environ.get("FACE_API_KEY", "")
DEFAULT_NUM_JITTERS = int(os.environ.get("FACE_NUM_JITTERS", "1"))
DEFAULT_UPSAMPLE_TIMES = int(os.environ.get("FACE_UPSAMPLE_TIMES", "1"))
DEFAULT_DETECTION_MODEL = os.environ.get("FACE_DETECTION_MODEL", "hog")  # hog|cnn
DEFAULT_DISTANCE_METRIC = os.environ.get("FACE_DISTANCE_METRIC", "linear")  # linear|rbf (svm kernel)
DEFAULT_SVM_C = float(os.environ.get("FACE_SVM_C", "1.0"))
DEFAULT_MIN_FACE_SIZE = int(os.environ.get("FACE_MIN_FACE_SIZE", "40"))  # pixels (heuristic on bbox)
DEFAULT_ALLOW_MULTI_FACE = os.environ.get("FACE_ALLOW_MULTI_FACE", "true").lower() == "true"


_model_lock = threading.RLock()


class TrainRequest(BaseModel):
    train_dir: str = Field(default=DEFAULT_TRAIN_DIR)
    model_path: str = Field(default=DEFAULT_MODEL_PATH)
    detection_model: str = Field(default=DEFAULT_DETECTION_MODEL)
    upsample_times: int = Field(default=DEFAULT_UPSAMPLE_TIMES, ge=0, le=4)
    num_jitters: int = Field(default=DEFAULT_NUM_JITTERS, ge=1, le=100)
    svm_kernel: str = Field(default=DEFAULT_DISTANCE_METRIC)  # linear|rbf
    svm_c: float = Field(default=DEFAULT_SVM_C, gt=0.0)
    allow_multi_face: bool = Field(default=DEFAULT_ALLOW_MULTI_FACE)
    min_face_size: int = Field(default=DEFAULT_MIN_FACE_SIZE, ge=10, le=500)


class PredictResponse(BaseModel):
    model_fingerprint: str
    classes: List[str]
    probabilities: Dict[str, float]
    top_class: str
    top_probability: float
    face_count: int
    faces: Optional[List[Dict[str, Any]]] = None


class ModelBundle:
    def __init__(
        self,
        le: LabelEncoder,
        clf: Pipeline,
        classes: List[str],
        fingerprint: str,
        train_dir: str,
        meta: Dict[str, Any],
    ):
        self.le = le
        self.clf = clf
        self.classes = classes
        self.fingerprint = fingerprint
        self.train_dir = train_dir
        self.meta = meta


def _require_api_key(x_api_key: str = Query(default="", alias="api_key")):
    if DEFAULT_API_KEY:
        if x_api_key != DEFAULT_API_KEY:
            raise HTTPException(status_code=401, detail="Unauthorized")
    return True


def _sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def _is_image_file(name: str) -> bool:
    n = name.lower()
    return n.endswith(".jpg") or n.endswith(".jpeg") or n.endswith(".png") or n.endswith(".bmp")


def _load_image_from_bytes(b: bytes) -> np.ndarray:
    try:
        img = Image.open(io.BytesIO(b)).convert("RGB")
        return np.array(img)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image: {e}")


def _extract_encodings(
    rgb: np.ndarray,
    detection_model: str,
    upsample_times: int,
    num_jitters: int,
    allow_multi_face: bool,
    min_face_size: int,
) -> Tuple[List[np.ndarray], List[Tuple[int, int, int, int]]]:
    locs = face_recognition.face_locations(rgb, number_of_times_to_upsample=upsample_times, model=detection_model)
    filtered_locs = []
    for (top, right, bottom, left) in locs:
        if (right - left) >= min_face_size and (bottom - top) >= min_face_size:
            filtered_locs.append((top, right, bottom, left))

    if not filtered_locs:
        return [], []

    if not allow_multi_face and len(filtered_locs) > 1:
        areas = [max(1, (r - l)) * max(1, (b - t)) for (t, r, b, l) in filtered_locs]
        filtered_locs = [filtered_locs[int(np.argmax(areas))]]

    encs = face_recognition.face_encodings(rgb, known_face_locations=filtered_locs, num_jitters=num_jitters)
    encs = [np.asarray(e, dtype=np.float32) for e in encs]
    return encs, filtered_locs


def _scan_training_data(
    train_dir: str,
    detection_model: str,
    upsample_times: int,
    num_jitters: int,
    allow_multi_face: bool,
    min_face_size: int,
) -> Tuple[np.ndarray, np.ndarray, Dict[str, Any]]:
    if not os.path.isdir(train_dir):
        raise HTTPException(status_code=400, detail=f"train_dir not found: {train_dir}")

    X = []
    y = []
    per_class_counts = {}
    skipped = []
    processed = 0

    for cls in sorted(os.listdir(train_dir)):
        cls_path = os.path.join(train_dir, cls)
        if not os.path.isdir(cls_path):
            continue

        per_class_counts.setdefault(cls, {"images": 0, "faces": 0, "skipped_images": 0})
        for fn in sorted(os.listdir(cls_path)):
            if not _is_image_file(fn):
                continue
            per_class_counts[cls]["images"] += 1
            img_path = os.path.join(cls_path, fn)
            try:
                rgb = face_recognition.load_image_file(img_path)
                encs, locs = _extract_encodings(
                    rgb=rgb,
                    detection_model=detection_model,
                    upsample_times=upsample_times,
                    num_jitters=num_jitters,
                    allow_multi_face=allow_multi_face,
                    min_face_size=min_face_size,
                )
                if not encs:
                    per_class_counts[cls]["skipped_images"] += 1
                    skipped.append({"path": img_path, "reason": "no_face_found"})
                    continue

                for e in encs:
                    X.append(e)
                    y.append(cls)
                per_class_counts[cls]["faces"] += len(encs)
                processed += 1
            except Exception as e:
                per_class_counts[cls]["skipped_images"] += 1
                skipped.append({"path": img_path, "reason": str(e)})

    if len(X) < 2:
        raise HTTPException(status_code=400, detail="Not enough training samples. Need at least 2 face encodings.")

    meta = {
        "train_dir": train_dir,
        "detection_model": detection_model,
        "upsample_times": upsample_times,
        "num_jitters": num_jitters,
        "allow_multi_face": allow_multi_face,
        "min_face_size": min_face_size,
        "per_class_counts": per_class_counts,
        "skipped": skipped[:2000],
        "processed_images": processed,
        "total_faces": int(len(X)),
    }
    return np.vstack(X), np.array(y), meta


def _build_model(
    X: np.ndarray,
    y: np.ndarray,
    svm_kernel: str,
    svm_c: float,
) -> Tuple[LabelEncoder, Pipeline]:
    le = LabelEncoder()
    y_enc = le.fit_transform(y)

    kernel = svm_kernel.lower().strip()
    if kernel not in ("linear", "rbf"):
        raise HTTPException(status_code=400, detail="svm_kernel must be 'linear' or 'rbf'")

    clf = SVC(kernel=kernel, C=svm_c, probability=True, class_weight="balanced", random_state=42)
    clf.fit(X, y_enc)

    pipeline = Pipeline([("svc", clf)])
    return le, pipeline


def _fingerprint_model(le: LabelEncoder, clf: Pipeline, meta: Dict[str, Any]) -> str:
    blob = pickle.dumps({"classes": le.classes_.tolist(), "clf": clf, "meta": meta}, protocol=pickle.HIGHEST_PROTOCOL)
    return _sha256_bytes(blob)


def _save_model_bundle(path: str, bundle: ModelBundle):
    os.makedirs(os.path.dirname(os.path.abspath(path)), exist_ok=True)
    data = {
        "le": bundle.le,
        "clf": bundle.clf,
        "classes": bundle.classes,
        "fingerprint": bundle.fingerprint,
        "train_dir": bundle.train_dir,
        "meta": bundle.meta,
        "version": 1,
    }
    with open(path, "wb") as f:
        pickle.dump(data, f, protocol=pickle.HIGHEST_PROTOCOL)


def _load_model_bundle(path: str) -> ModelBundle:
    if not os.path.isfile(path):
        raise HTTPException(status_code=404, detail=f"Model not found: {path}")
    with open(path, "rb") as f:
        data = pickle.load(f)
    if "le" not in data or "clf" not in data or "classes" not in data:
        raise HTTPException(status_code=500, detail="Invalid model file")
    return ModelBundle(
        le=data["le"],
        clf=data["clf"],
        classes=list(data["classes"]),
        fingerprint=data.get("fingerprint", ""),
        train_dir=data.get("train_dir", ""),
        meta=data.get("meta", {}),
    )


def _normalize_probs(classes: List[str], probs: np.ndarray) -> Dict[str, float]:
    probs = np.asarray(probs, dtype=np.float64)
    probs = np.maximum(probs, 0.0)
    s = float(probs.sum())
    if s <= 0:
        p = np.ones(len(classes), dtype=np.float64) / max(1, len(classes))
    else:
        p = probs / s
    return {cls: float(p[i]) for i, cls in enumerate(classes)}


def _predict_distribution_for_face(bundle: ModelBundle, enc: np.ndarray) -> Dict[str, float]:
    svc: SVC = bundle.clf.named_steps["svc"]
    probs = svc.predict_proba(enc.reshape(1, -1))[0]
    # Map svc class order (encoded labels) back to class names
    enc_classes = svc.classes_
    dist = {cls: 0.0 for cls in bundle.classes}
    for i, enc_label in enumerate(enc_classes):
        name = bundle.le.inverse_transform([enc_label])[0]
        dist[name] = float(probs[i])
    # Ensure normalized across all known classes
    return _normalize_probs(bundle.classes, np.array([dist[c] for c in bundle.classes], dtype=np.float64))


def _aggregate_face_distributions(classes: List[str], dists: List[Dict[str, float]]) -> Dict[str, float]:
    if not dists:
        return {c: 0.0 for c in classes}
    mat = np.array([[d[c] for c in classes] for d in dists], dtype=np.float64)
    avg = mat.mean(axis=0)
    return _normalize_probs(classes, avg)


app = FastAPI(title=APP_NAME, version="1.0")


@app.get("/health")
def health():
    return {"ok": True, "name": APP_NAME}


@app.post("/train")
def train(req: TrainRequest, _auth: bool = Depends(_require_api_key)):
    with _model_lock:
        X, y, meta = _scan_training_data(
            train_dir=req.train_dir,
            detection_model=req.detection_model,
            upsample_times=req.upsample_times,
            num_jitters=req.num_jitters,
            allow_multi_face=req.allow_multi_face,
            min_face_size=req.min_face_size,
        )
        le, clf = _build_model(X, y, svm_kernel=req.svm_kernel, svm_c=req.svm_c)
        fingerprint = _fingerprint_model(le, clf, meta)
        bundle = ModelBundle(
            le=le,
            clf=clf,
            classes=list(le.classes_),
            fingerprint=fingerprint,
            train_dir=req.train_dir,
            meta=meta,
        )
        _save_model_bundle(req.model_path, bundle)
        return {
            "model_path": req.model_path,
            "model_fingerprint": fingerprint,
            "classes": bundle.classes,
            "meta": meta,
        }


@app.get("/model/info")
def model_info(model_path: str = Query(default=DEFAULT_MODEL_PATH), _auth: bool = Depends(_require_api_key)):
    with _model_lock:
        bundle = _load_model_bundle(model_path)
        return {
            "model_path": model_path,
            "model_fingerprint": bundle.fingerprint,
            "classes": bundle.classes,
            "train_dir": bundle.train_dir,
            "meta": bundle.meta,
        }


@app.post("/predict", response_model=PredictResponse)
async def predict(
    file: UploadFile = File(...),
    model_path: str = Query(default=DEFAULT_MODEL_PATH),
    detection_model: str = Query(default=DEFAULT_DETECTION_MODEL),
    upsample_times: int = Query(default=DEFAULT_UPSAMPLE_TIMES, ge=0, le=4),
    num_jitters: int = Query(default=1, ge=1, le=100),
    allow_multi_face: bool = Query(default=DEFAULT_ALLOW_MULTI_FACE),
    min_face_size: int = Query(default=DEFAULT_MIN_FACE_SIZE, ge=10, le=500),
    include_faces: bool = Query(default=True),
    _auth: bool = Depends(_require_api_key),
):
    b = await file.read()
    if not b:
        raise HTTPException(status_code=400, detail="Empty file")

    rgb = _load_image_from_bytes(b)

    with _model_lock:
        bundle = _load_model_bundle(model_path)

    encs, locs = _extract_encodings(
        rgb=rgb,
        detection_model=detection_model,
        upsample_times=upsample_times,
        num_jitters=num_jitters,
        allow_multi_face=allow_multi_face,
        min_face_size=min_face_size,
    )

    if not encs:
        return PredictResponse(
            model_fingerprint=bundle.fingerprint,
            classes=bundle.classes,
            probabilities={c: 0.0 for c in bundle.classes},
            top_class="",
            top_probability=0.0,
            face_count=0,
            faces=[] if include_faces else None,
        )

    face_dists = []
    faces_payload = []
    for i, enc in enumerate(encs):
        dist = _predict_distribution_for_face(bundle, enc)
        face_dists.append(dist)
        if include_faces:
            (top, right, bottom, left) = locs[i]
            top_class = max(dist.items(), key=lambda kv: kv[1])[0]
            top_prob = float(dist[top_class])
            faces_payload.append(
                {
                    "index": i,
                    "box": {"top": int(top), "right": int(right), "bottom": int(bottom), "left": int(left)},
                    "probabilities": dist,
                    "top_class": top_class,
                    "top_probability": top_prob,
                }
            )

    agg = _aggregate_face_distributions(bundle.classes, face_dists)
    top_class = max(agg.items(), key=lambda kv: kv[1])[0] if bundle.classes else ""
    top_prob = float(agg.get(top_class, 0.0)) if top_class else 0.0

    return PredictResponse(
        model_fingerprint=bundle.fingerprint,
        classes=bundle.classes,
        probabilities=agg,
        top_class=top_class,
        top_probability=top_prob,
        face_count=len(encs),
        faces=faces_payload if include_faces else None,
    )


